export default function FilterPanel({ meta, platforms, genres, yearRange, onPlatforms, onGenres, onYearRange }) {
  const toggle = (list, setList, val) =>
    setList(list.includes(val) ? list.filter(v => v !== val) : [...list, val])

  const minPct = meta.minYear === meta.maxYear ? 0 : ((yearRange[0] - meta.minYear) / (meta.maxYear - meta.minYear)) * 100
  const maxPct = meta.minYear === meta.maxYear ? 100 : ((yearRange[1] - meta.minYear) / (meta.maxYear - meta.minYear)) * 100

  return (
    <div className="filters-grid">
      {/* Platform */}
      <div className="card">
        <div className="filter-header">
          <span className="section-label">Platform</span>
          <button className="reset-btn" onClick={() => onPlatforms([])}>Reset</button>
        </div>
        <div className="chips">
          {meta.platforms.map(p => (
            <button
              key={p}
              className={`chip${platforms.includes(p) ? ' active' : ''}`}
              onClick={() => toggle(platforms, onPlatforms, p)}
            >
              {p}
            </button>
          ))}
        </div>
      </div>

      {/* Genre */}
      <div className="card">
        <div className="filter-header">
          <span className="section-label">Genre</span>
          <button className="reset-btn" onClick={() => onGenres([])}>Reset</button>
        </div>
        <div className="chips">
          {meta.genres.map(g => (
            <button
              key={g}
              className={`chip${genres.includes(g) ? ' active' : ''}`}
              onClick={() => toggle(genres, onGenres, g)}
            >
              {g}
            </button>
          ))}
        </div>
      </div>

      {/* Year Range */}
      <div className="card">
        <div className="filter-header">
          <span className="section-label">Year of Release</span>
          <button className="reset-btn" onClick={() => onYearRange([meta.minYear, meta.maxYear])}>Reset</button>
        </div>
        <div className="year-range">
          <div className="year-slider-row">
            <span className="year-label">{meta.minYear}</span>
            <input
              type="range"
              min={meta.minYear}
              max={meta.maxYear}
              value={yearRange[0]}
              style={{ background: `linear-gradient(to right, #e5e7eb ${minPct}%, #22c55e ${minPct}%, #22c55e ${maxPct}%, #e5e7eb ${maxPct}%)` }}
              onChange={e => {
                const v = Number(e.target.value)
                if (v <= yearRange[1]) onYearRange([v, yearRange[1]])
              }}
            />
            <input
              type="range"
              min={meta.minYear}
              max={meta.maxYear}
              value={yearRange[1]}
              style={{ background: 'transparent' }}
              onChange={e => {
                const v = Number(e.target.value)
                if (v >= yearRange[0]) onYearRange([yearRange[0], v])
              }}
            />
            <span className="year-label" style={{ textAlign: 'right' }}>{meta.maxYear}</span>
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, fontWeight: 600, color: '#111827' }}>
            <span>{yearRange[0]}</span>
            <span>{yearRange[1]}</span>
          </div>
        </div>
      </div>
    </div>
  )
}

import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts'

const ACCENT = '#22c55e'

export default function GenreBarChart({ data }) {
  const counts = {}
  data.forEach(g => { counts[g.Genre] = (counts[g.Genre] || 0) + 1 })
  const chartData = Object.entries(counts)
    .map(([genre, count]) => ({ genre, count }))
    .sort((a, b) => b.count - a.count)

  return (
    <div className="card" style={{ height: 360 }}>
      <div className="chart-header">
        <span className="section-label">Games by Genre</span>
      </div>
      <ResponsiveContainer width="100%" height="90%">
        <BarChart data={chartData} layout="vertical" margin={{ left: 8, right: 16, top: 0, bottom: 0 }}>
          <XAxis type="number" tick={{ fontSize: 11, fill: '#9ca3af' }} axisLine={false} tickLine={false} />
          <YAxis type="category" dataKey="genre" width={90} tick={{ fontSize: 11, fill: '#6b7280' }} axisLine={false} tickLine={false} />
          <Tooltip
            formatter={v => [v, 'Games']}
            contentStyle={{ border: '1px solid #e5e7eb', borderRadius: 8, fontSize: 12 }}
            cursor={{ fill: '#f9fafb' }}
          />
          <Bar dataKey="count" radius={[0, 4, 4, 0]}>
            {chartData.map((_, i) => <Cell key={i} fill={ACCENT} />)}
          </Bar>
        </BarChart>
      </ResponsiveContainer>
    </div>
  )
}

import { PieChart, Pie, Cell, Tooltip, Legend, ResponsiveContainer } from 'recharts'

const COLORS = ['#60A5FA','#FB923C','#F472B6','#38BDF8','#FBBF24','#4ADE80','#A78BFA','#F87171','#E879F9','#86EFAC','#34D399','#FCD34D']

export default function PlatformPieChart({ data }) {
  const counts = {}
  data.forEach(g => { counts[g.Platform] = (counts[g.Platform] || 0) + 1 })
  const chartData = Object.entries(counts)
    .map(([platform, value]) => ({ platform, value }))
    .sort((a, b) => b.value - a.value)

  return (
    <div className="card" style={{ height: 360 }}>
      <div className="chart-header">
        <span className="section-label">Platform Distribution</span>
      </div>
      <ResponsiveContainer width="100%" height="90%">
        <PieChart>
          <Pie
            data={chartData}
            dataKey="value"
            nameKey="platform"
            cx="50%"
            cy="45%"
            innerRadius="40%"
            outerRadius="65%"
            paddingAngle={2}
          >
            {chartData.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
          </Pie>
          <Tooltip
            formatter={(v, name) => [v, name]}
            contentStyle={{ border: '1px solid #e5e7eb', borderRadius: 8, fontSize: 12 }}
          />
          <Legend
            iconType="circle"
            iconSize={8}
            formatter={v => <span style={{ fontSize: 11, color: '#6b7280' }}>{v}</span>}
          />
        </PieChart>
      </ResponsiveContainer>
    </div>
  )
}

import { LineChart, Line, XAxis, YAxis, Tooltip, Legend, ResponsiveContainer, CartesianGrid } from 'recharts'

const GENRE_COLORS = {
  Action: '#60A5FA', Adventure: '#4ADE80', Fighting: '#F472B6',
  Misc: '#A78BFA', Platform: '#FB923C', Puzzle: '#38BDF8',
  Racing: '#FBBF24', 'Role-Playing': '#F87171', Shooter: '#E879F9',
  Simulation: '#86EFAC', Sports: '#34D399', Strategy: '#FCD34D',
}

export default function ReleasesLineChart({ data }) {
  const genres = [...new Set(data.map(g => g.Genre))].sort()
  const years  = [...new Set(data.map(g => g.Year_of_Release))].sort()

  const chartData = years.map(year => {
    const row = { year }
    const yearGames = data.filter(g => g.Year_of_Release === year)
    genres.forEach(genre => {
      row[genre] = yearGames.filter(g => g.Genre === genre).length
    })
    return row
  })

  return (
    <div className="card" style={{ height: 360 }}>
      <div className="chart-header">
        <span className="section-label">Releases Over Time by Genre</span>
        <span className="chart-note">per year</span>
      </div>
      <ResponsiveContainer width="100%" height="88%">
        <LineChart data={chartData} margin={{ left: 0, right: 8, top: 0, bottom: 0 }}>
          <CartesianGrid stroke="#f3f4f6" vertical={false} />
          <XAxis dataKey="year" tick={{ fontSize: 11, fill: '#9ca3af' }} axisLine={false} tickLine={false} />
          <YAxis tick={{ fontSize: 11, fill: '#9ca3af' }} axisLine={false} tickLine={false} width={28} />
          <Tooltip contentStyle={{ border: '1px solid #e5e7eb', borderRadius: 8, fontSize: 12 }} />
          <Legend
            iconType="circle"
            iconSize={7}
            wrapperStyle={{ fontSize: 11, paddingTop: 4 }}
            formatter={v => <span style={{ color: '#6b7280' }}>{v}</span>}
          />
          {genres.map(genre => (
            <Line
              key={genre}
              type="monotone"
              dataKey={genre}
              stroke={GENRE_COLORS[genre] || '#9ca3af'}
              strokeWidth={2}
              dot={false}
              activeDot={{ r: 4 }}
            />
          ))}
        </LineChart>
      </ResponsiveContainer>
    </div>
  )
}

import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell, CartesianGrid } from 'recharts'

const COLORS = ['#60A5FA','#FB923C','#F472B6','#38BDF8','#FBBF24','#4ADE80','#A78BFA','#F87171','#E879F9','#86EFAC','#34D399','#FCD34D']

export default function PlatformScoreBar({ data }) {
  const totals = {}
  const counts = {}
  data.forEach(g => {
    totals[g.Platform] = (totals[g.Platform] || 0) + g.User_Score
    counts[g.Platform] = (counts[g.Platform] || 0) + 1
  })
  const chartData = Object.keys(totals)
    .map((p, i) => ({ platform: p, avg: +(totals[p] / counts[p]).toFixed(2), color: COLORS[i % COLORS.length] }))
    .sort((a, b) => b.avg - a.avg)

  return (
    <div className="card" style={{ height: 280 }}>
      <div className="chart-header">
        <span className="section-label">Avg User Score by Platform</span>
        <span className="chart-note">scale 0–10</span>
      </div>
      <ResponsiveContainer width="100%" height="85%">
        <BarChart data={chartData} margin={{ left: 0, right: 8, top: 0, bottom: 0 }}>
          <CartesianGrid stroke="#f3f4f6" vertical={false} />
          <XAxis dataKey="platform" tick={{ fontSize: 12, fill: '#6b7280' }} axisLine={false} tickLine={false} />
          <YAxis domain={[0, 10]} tick={{ fontSize: 11, fill: '#9ca3af' }} axisLine={false} tickLine={false} width={28} />
          <Tooltip
            formatter={v => [v, 'Avg User Score']}
            contentStyle={{ border: '1px solid #e5e7eb', borderRadius: 8, fontSize: 12 }}
            cursor={{ fill: '#f9fafb' }}
          />
          <Bar dataKey="avg" radius={[4, 4, 0, 0]} maxBarSize={48}>
            {chartData.map((entry, i) => <Cell key={i} fill={entry.color} />)}
          </Bar>
        </BarChart>
      </ResponsiveContainer>
    </div>
  )
}

