import { PieChart, Pie, Cell, Tooltip, Legend, ResponsiveContainer } from 'recharts'

const COLORS = ['#60A5FA','#FB923C','#F472B6','#38BDF8','#FBBF24','#4ADE80','#A78BFA','#F87171','#E879F9','#86EFAC','#34D399','#FCD34D']

export default function PlatformPieChart({ data }) {
  const counts = {}
  data.forEach(g => { counts[g.Platform] = (counts[g.Platform] || 0) + 1 })
  const chartData = Object.entries(counts)
    .map(([platform, value]) => ({ platform, value }))
    .sort((a, b) => b.value - a.value)

  return (
    <div className="card" style={{ height: 360 }}>
      <div className="chart-header">
        <span className="section-label">Platform Distribution</span>
      </div>
      <ResponsiveContainer width="100%" height="90%">
        <PieChart>
          <Pie
            data={chartData}
            dataKey="value"
            nameKey="platform"
            cx="50%"
            cy="45%"
            innerRadius="40%"
            outerRadius="65%"
            paddingAngle={2}
          >
            {chartData.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
          </Pie>
          <Tooltip
            formatter={(v, name) => [v, name]}
            contentStyle={{ border: '1px solid #e5e7eb', borderRadius: 8, fontSize: 12 }}
          />
          <Legend
            iconType="circle"
            iconSize={8}
            formatter={v => <span style={{ fontSize: 11, color: '#6b7280' }}>{v}</span>}
          />
        </PieChart>
      </ResponsiveContainer>
    </div>
  )
}

