import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell, CartesianGrid } from 'recharts'

const COLORS = ['#60A5FA','#FB923C','#F472B6','#38BDF8','#FBBF24','#4ADE80','#A78BFA','#F87171','#E879F9','#86EFAC','#34D399','#FCD34D']

export default function PlatformPieChart({ data }) {
  const counts = {}
  data.forEach(g => { counts[g.Platform] = (counts[g.Platform] || 0) + 1 })
  const chartData = Object.entries(counts)
    .map(([platform, value], i) => ({ platform, value, color: COLORS[i % COLORS.length] }))
    .sort((a, b) => b.value - a.value)

  return (
    <div className="card" style={{ height: 360 }}>
      <div className="chart-header">
        <span className="section-label">Platform Distribution</span>
      </div>
      <ResponsiveContainer width="100%" height="90%">
