          <CartesianGrid stroke="#f3f4f6" vertical={false} />
          <XAxis dataKey="platform" tick={{ fontSize: 12, fill: '#6b7280' }} axisLine={false} tickLine={false} />
          <YAxis tick={{ fontSize: 11, fill: '#9ca3af' }} axisLine={false} tickLine={false} width={36} />
