        <PieChart>
          <Pie
            data={chartData}
            dataKey="value"
            nameKey="platform"
            cx="50%"
            cy="45%"
            innerRadius="40%"
            outerRadius="65%"
            paddingAngle={2}
          >
            {chartData.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
